+/// Diagnostic event types for JSONL logging.
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+pub enum DiagnosticEventKind {
+    /// Search query changed.
+    QueryChange,
+    /// Filter updated with results.
+    FilterUpdate,
+    /// Selection moved.
+    Navigate,
+    /// Focus changed between search and list.
+    FocusChange,
+    /// Page scroll (up/down).
+    PageScroll,
+    /// Jump to first/last.
+    JumpToEdge,
